mapper.select:
with artists as ( select a.id, a.name, a.type, role, sa.song_id from artist a inner join song_artist sa on a.id = sa.artist_id join lateral jsonb_array_elements_text(sa.roles) as role on true union all select a.id, a.name, a.type, 'ALBUM_ARTIST' role, s.id song_id from artist a inner join album al on a.id = al.primary_artist_id inner join song s on al.id = s.album_id ) select id, name, type, jsonb_agg(distinct role) matched_roles from artists where exists(select * from transcription t where t.song_id = artists.song_id)
#{role}
and name ~* #{criteria.searchName}
and type = #{criteria.type}
group by id, name, type

exists(select * from transcription t where t.pub_id = p.id)
and (name ~* #{criteria.searchName} or coalesce(details->>'issueName', details->>'edition') ~* #{criteria.searchName})
and pi.type = #{criteria.type}::pub_type
p.pub_date >= #{criteria.dateStart}
and p.pub_date <= #{criteria.dateEnd}
order by p.pub_date nulls first, pi.name, p.details->>'volume' nulls first, p.details->>'issue' nulls first, p.details->>'issueName' nulls first, p.details->>'edition' nulls first, p.id

select a.id, a.title, d.release_date, d.album_cover_url, case when a.primary_artist_id is not null then json_build_object('id', aa.id, 'name', aa.name, 'type', aa.type) end artist from album a join lateral (select case when (a.details->>'releaseDate') ~ '^\d\d\d\d-\d\d-\d\d$' then (a.details->>'releaseDate')::date end release_date, a.details->>'albumCoverUrl' album_cover_url ) as d on true left join artist aa on a.primary_artist_id = aa.id where exists(select * from transcription t inner join song s on t.song_id = s.id where s.album_id = a.id)
and (a.title ~* #{criteria.searchName} or aa.name ~* #{criteria.searchName})
d.release_date >= #{criteria.dateStart}
and d.release_date <= #{criteria.dateEnd}
order by d.release_date nulls first, a.title, aa.name nulls first, a.id
